import type { TransactionDirection } from "@dfp/bw-isomorphic-enums";

import { CashflowTableCell } from "../CashflowTableCell.tsx";
import type {
  CashflowPeriod,
  CategoryOption,
  CategoryType,
} from "../types/index.ts";
import { getCategoryLabel } from "../utils/index.ts";
import {
  CashflowCategoryRow,
  CashflowCategoryRowLabel,
} from "./CashflowCategory.tsx";
import { useCashflowTable } from "./CashflowTableContext.tsx";
import { useOpenCategoryDetail } from "./categoryDetail/index.ts";

type CashflowCategoryDataRowProps = {
  allCategories: Array<CategoryOption>;
  category: CategoryType;
  direction: TransactionDirection;
};

export function CashflowCategoryDataRow({
  allCategories,
  category,
  direction,
}: CashflowCategoryDataRowProps) {
  const { data } = useCashflowTable();
  const categoryLabel = getCategoryLabel(category, allCategories);

  const openDetail = useOpenCategoryDetail({
    category,
    direction,
    categoryLabel,
  });

  const getCategoryValue = (period: CashflowPeriod) =>
    (direction === "IN" ? period.incomeCategories : period.costsCategories).get(
      category,
    ) ?? 0;

  return (
    <CashflowCategoryRow>
      <CashflowCategoryRowLabel category={category} direction={direction}>
        {categoryLabel}
      </CashflowCategoryRowLabel>

      {data?.periods.map((period, index) => (
        <CashflowTableCell
          key={period.id}
          value={getCategoryValue(period)}
          columnIndex={index}
          dateFrom={period.dateFrom}
          colorMode="none"
          onClick={() => openDetail(index)}
        />
      ))}
    </CashflowCategoryRow>
  );
}

