  kind="summary"
  label={tt("cashflowTable.rows.netBalance")}
  cells={data.periods.map((period, columnIndex) => ({
    value: period.netBalance,
    columnIndex,
    dateFrom: period.dateFrom,
    isBold: true,
    colorMode: "balance",
  }))}
